// Parse sitemap XML, recursing into <sitemapindex> children when present.
// Sandbox-safe: avoids the `URL` and `fetch` globals (some n8n VM2 setups
// don't expose them) and uses `this.helpers.httpRequest` for HTTP.
const cfg = $('Indexing Config').first().json;
const raw = $input.first().json;
const body = typeof raw === 'string' ? raw : (raw.data || raw.body || '');

let helpers = null;
try { if (this && this.helpers) helpers = this.helpers; } catch (e) {}

const allowPatterns = (cfg.allowPathPatterns || '').split(',').map(s => s.trim()).filter(Boolean);
const blockPatterns = (cfg.blockPathPatterns || '').split(',').map(s => s.trim()).filter(Boolean);
const localePrefixRe = /^\/(fr|ar|en-uk|fr-uk|ar-uk|en-fr|fr-fr|ar-fr)(\/|$)/i;

function pathOf(url) {
  if (typeof url !== 'string') return null;
  const m = url.match(/^https?:\/\/[^\/?#]+([^?#]*)/i);
  return m ? (m[1] || '/') : null;
}

function allowed(url) {
  const path = pathOf(url);
  if (!path) return false;
  if (localePrefixRe.test(path)) return false;
  if (blockPatterns.some(p => path.startsWith(p))) return false;
  if (allowPatterns.length === 0) return true;
  return allowPatterns.some(p => path === p || path.startsWith(p));
}

function normalize(url) {
  if (typeof url !== 'string') return null;
  let s = url.trim();
  if (!s) return null;
  const hashIdx = s.indexOf('#');
  if (hashIdx >= 0) s = s.slice(0, hashIdx);
  if (!/^https?:\/\//i.test(s)) return null;
  // Split path and query so we can normalize each independently.
  const qIdx = s.indexOf('?');
  let base = qIdx >= 0 ? s.slice(0, qIdx) : s;
  let query = qIdx >= 0 ? s.slice(qIdx + 1) : '';
  // Collapse /collections/<X>/products/<Y> -> /products/<Y> so collection-
  // scoped product URLs dedupe to the canonical product URL.
  const cp = base.match(/^(https?:\/\/[^\/]+)\/collections\/[^\/]+\/products\/([^\/]+)/i);
  if (cp) base = cp[1] + '/products/' + cp[2];
  // Strip trailing slash from non-root paths so `/foo/` and `/foo` dedupe.
  base = base.replace(/^(https?:\/\/[^\/]+)\/+$/i, '$1');
  base = base.replace(/^(https?:\/\/[^\/]+)(\/.+?)\/+$/i, '$1$2');
  // For Shopify product/collection pages, drop ALL query params (variant=, etc).
  // For other pages, only drop tracking params.
  if (/\/(products|collections)\/[^\/]+$/i.test(base)) {
    query = '';
  } else if (query) {
    const drop = ['utm_source','utm_medium','utm_campaign','utm_content','utm_term','gclid','fbclid'];
    const kept = query.split('&').filter(p => p && !drop.includes(p.split('=')[0]));
    query = kept.join('&');
  }
  return query ? base + '?' + query : base;
}

function decodeXmlEntities(s) {
  return String(s)
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'");
}

function extractEntries(xml, tag) {
  const re = new RegExp('<' + tag + '\\b[^>]*>[\\s\\S]*?<\\/' + tag + '>', 'g');
  const blocks = xml.match(re) || [];
  const out = [];
  for (const block of blocks) {
    const loc = (block.match(/<loc>([^<]+)<\/loc>/) || [])[1];
    const lastmod = (block.match(/<lastmod>([^<]+)<\/lastmod>/) || [])[1];
    const priority = parseFloat((block.match(/<priority>([^<]+)<\/priority>/) || [])[1] || '0.5');
    if (loc) out.push({ loc: decodeXmlEntities(loc.trim()), lastmod: lastmod ? lastmod.trim() : null, priority });
  }
  return out;
}

async function fetchXml(url) {
  if (!helpers) return '';
  const opts = {
    method: 'GET',
    url: url,
    headers: { 'User-Agent': cfg.userAgent || 'MarbleBeeIndexerBot/1.0' },
    returnFullResponse: false,
  };
  try {
    if (typeof helpers.httpRequest === 'function') {
      const res = await helpers.httpRequest(opts);
      return typeof res === 'string' ? res : String(res || '');
    }
    if (typeof helpers.request === 'function') {
      const res = await helpers.request({ method: 'GET', uri: url, headers: opts.headers, json: false });
      return typeof res === 'string' ? res : String(res || '');
    }
    return '';
  } catch (e) {
    return '';
  }
}

function ingestUrlset(xml, urls) {
  const entries = extractEntries(xml, 'url');
  for (const e of entries) {
    const u = normalize(e.loc);
    if (u && allowed(u) && !urls.has(u)) {
      urls.set(u, { url: u, lastmod: e.lastmod, priority: e.priority, source: 'sitemap' });
    }
    if (urls.size >= cfg.maxPages) return;
  }
}

const urls = new Map();

if (typeof body === 'string' && (body.includes('<urlset') || body.includes('<sitemapindex'))) {
  if (body.includes('<sitemapindex')) {
    const children = extractEntries(body, 'sitemap');
    for (const c of children) {
      if (urls.size >= cfg.maxPages) break;
      const childPath = pathOf(c.loc);
      if (childPath && localePrefixRe.test(childPath)) continue;
      const childXml = await fetchXml(c.loc);
      if (childXml) ingestUrlset(childXml, urls);
    }
  } else {
    ingestUrlset(body, urls);
  }
}

// Always include the home page so it never goes missing
const home = (cfg.siteBaseUrl || '').trim();
if (home && /^https?:\/\//i.test(home) && !urls.has(home)) {
  urls.set(home, { url: home, lastmod: null, priority: 1.0, source: 'seed' });
}

const out = Array.from(urls.values())
  .sort((a, b) => (b.priority || 0) - (a.priority || 0))
  .slice(cfg.startPage || 0, (cfg.startPage || 0) + cfg.maxPages);

return out.map(u => ({ json: u }));

// Build a clean indexable document. For Shopify product / collection JSON
// endpoints, extract structured fields (title, description, price, variants)
// and skip storefront chrome. For everything else, fall back to HTML strip.
// Sandbox-safe: pure-JS hash, this.helpers.httpRequest only.
let urlInfo;
try { urlInfo = $('Split In Batches').item.json; } catch (e) {}
if (!urlInfo || !urlInfo.url) { try { urlInfo = $('Split In Batches').context && $('Split In Batches').context.currentItem; } catch (e) {} }
if (!urlInfo) urlInfo = $input.first().json || {};

const cfg = $('Indexing Config').first().json || {};
const raw = $input.first().json || {};

const bodyRaw = typeof raw.body === 'string' ? raw.body : (typeof raw.data === 'string' ? raw.data : (typeof raw === 'string' ? raw : ''));
const headers = (raw.headers || {});
const lastModifiedHttp = headers['last-modified'] || headers['Last-Modified'] || null;
const statusCode = raw.statusCode != null ? raw.statusCode : (raw.status != null ? raw.status : 200);

// Canonicalize the page URL we record: strip query/fragment, trailing slash,
// and collapse /collections/X/products/Y -> /products/Y so that variants and
// collection-scoped product URLs dedupe to a single source row.
function canonicalize(u) {
  if (typeof u !== 'string') return u;
  let s = u.replace(/[?#].*$/, '').replace(/\/+$/, '');
  const m = s.match(/^(https?:\/\/[^\/]+)\/collections\/[^\/]+\/products\/([^\/]+)$/);
  if (m) s = m[1] + '/products/' + m[2];
  return s;
}

const canonicalUrl = canonicalize(urlInfo.url);
const productMatch = canonicalUrl.match(/^https?:\/\/[^\/]+\/products\/([^\/?#]+)$/i);
const collectionMatch = canonicalUrl.match(/^https?:\/\/[^\/]+\/collections\/([^\/?#]+)$/i);

let helpers = null;
try { if (this && this.helpers) helpers = this.helpers; } catch (e) {}

async function fetchJson(url) {
  if (!helpers || typeof helpers.httpRequest !== 'function') return null;
  try {
    const res = await helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': cfg.userAgent || 'MarbleBeeIndexerBot/1.0' },
      json: true,
      returnFullResponse: false,
    });
    return res;
  } catch (e) { return null; }
}

function tryParseJson(s) {
  if (typeof s !== 'string') return null;
  try { return JSON.parse(s); } catch (e) { return null; }
}

function htmlToText(html) {
  let t = String(html || '');
  t = t.replace(/<script[\s\S]*?<\/script>/gi, ' ');
  t = t.replace(/<style[\s\S]*?<\/style>/gi, ' ');
  t = t.replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ');
  t = t.replace(/<!--[\s\S]*?-->/g, ' ');
  // Block-level closes -> paragraph breaks (\n\n) so the splitter can keep
  // each section in its own chunk and the title-prefix step below has natural
  // boundaries to repeat the product name on.
  t = t.replace(/<\/(p|div|li|h[1-6]|tr|section|article)>/gi, '\n\n');
  t = t.replace(/<br\s*\/?>/gi, '\n');
  t = t.replace(/<[^>]+>/g, ' ');
  t = t
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&[a-z]+;/gi, ' ');
  // Trim each line, drop pure-whitespace lines, then collapse 3+ blank lines
  // into a single paragraph break.
  return t.split('\n').map(l => l.replace(/[ \t]+/g, ' ').trim()).join('\n')
    .replace(/\n{3,}/g, '\n\n').replace(/^\s+|\s+$/g, '');
}

function fmtMoney(n) {
  if (n == null || n === '') return null;
  const v = Number(n);
  if (!isFinite(v)) return null;
  return v.toFixed(2);
}

function cyrb128(str) {
  let h1 = 1779033703, h2 = 3144134277, h3 = 1013904242, h4 = 2773480762;
  for (let i = 0; i < str.length; i++) {
    const k = str.charCodeAt(i);
    h1 = h2 ^ Math.imul(h1 ^ k, 597399067);
    h2 = h3 ^ Math.imul(h2 ^ k, 2869860233);
    h3 = h4 ^ Math.imul(h3 ^ k, 951274213);
    h4 = h1 ^ Math.imul(h4 ^ k, 2716044179);
  }
  h1 = Math.imul(h3 ^ (h1 >>> 18), 597399067);
  h2 = Math.imul(h4 ^ (h2 >>> 22), 2869860233);
  h3 = Math.imul(h1 ^ (h3 >>> 17), 951274213);
  h4 = Math.imul(h2 ^ (h4 >>> 19), 2716044179);
  h1 ^= (h2 ^ h3 ^ h4); h2 ^= h1; h3 ^= h1; h4 ^= h1;
  return [h1 >>> 0, h2 >>> 0, h3 >>> 0, h4 >>> 0]
    .map(n => n.toString(16).padStart(8, '0')).join('');
}

if (statusCode >= 400 || !bodyRaw) {
  return [{ json: { url: canonicalUrl, skip: true, skipReason: `fetch failed (status ${statusCode})` } }];
}

const json = tryParseJson(bodyRaw);
const isProductJson = !!(json && json.product && typeof json.product === 'object');
const isCollectionJson = !!(json && json.collection && typeof json.collection === 'object');

// --- PRODUCT branch: structured Shopify product ---
if (productMatch && isProductJson) {
  const p = json.product;
  const title = (p.title || '').trim();
  const vendor = (p.vendor || '').trim();
  const productType = (p.product_type || '').trim();
  const tags = (typeof p.tags === 'string'
    ? p.tags.split(',').map(s => s.trim()).filter(Boolean)
    : (Array.isArray(p.tags) ? p.tags : []));
  const bodyText = htmlToText(p.body_html || '');

  const variants = Array.isArray(p.variants) ? p.variants : [];
  const prices = variants.map(v => Number(v && v.price)).filter(n => isFinite(n) && n > 0);
  const priceMin = prices.length ? Math.min(...prices) : null;
  const priceMax = prices.length ? Math.max(...prices) : null;

  const lines = [];
  if (title) lines.push(`# ${title}`);
  if (priceMin != null) {
    if (priceMax != null && priceMax !== priceMin) {
      lines.push(`Price: $${fmtMoney(priceMin)} – $${fmtMoney(priceMax)}`);
    } else {
      lines.push(`Price: $${fmtMoney(priceMin)}`);
    }
  }
  if (vendor) lines.push(`Vendor: ${vendor}`);
  if (productType) lines.push(`Product type: ${productType}`);
  if (tags.length) lines.push(`Tags: ${tags.join(', ')}`);
  if (variants.length > 1) {
    const variantLines = variants.map(v => {
      const name = (v && v.title && v.title !== 'Default Title') ? v.title : null;
      const price = fmtMoney(v && v.price);
      const sku = v && v.sku;
      const parts = [];
      if (name) parts.push(name);
      if (price) parts.push('$' + price);
      if (sku) parts.push('SKU ' + sku);
      return parts.length ? '- ' + parts.join(' — ') : null;
    }).filter(Boolean);
    if (variantLines.length) {
      lines.push('');
      lines.push('Variants:');
      lines.push(...variantLines);
    }
  }
  if (bodyText) {
    // Prefix every paragraph with the product title so each chunk the
    // downstream splitter produces still contains the product name.
    // Without this, FTS misses compound queries like "Triangle stone basin
    // weight" because the weight line and the title end up in different chunks.
    const titlePrefix = title ? `# ${title} \u2014 ` : '';
    const paragraphs = bodyText.split(/\n\n+/);
    for (const para of paragraphs) {
      const trimmed = para.trim();
      if (!trimmed) continue;
      lines.push('');
      lines.push(titlePrefix + trimmed);
    }
  }

  const composed = lines.join('\n');
  if (composed.length < 40) {
    return [{ json: { url: canonicalUrl, skip: true, skipReason: 'product doc too small' } }];
  }

  const productHandle = p.handle || productMatch[1];
  const lastModified = p.updated_at || p.created_at || lastModifiedHttp || urlInfo.lastmod || null;

  return [{
    json: {
      url: canonicalUrl,
      page_title: title || null,
      meta_description: null,
      last_modified: lastModified,
      content: composed,
      content_hash: cyrb128(composed),
      char_count: composed.length,
      doc_type: 'product',
      product_handle: productHandle,
      collection_handle: null,
      price_min: priceMin,
      price_max: priceMax,
      skip: false
    }
  }];
}

// --- COLLECTION branch: collection metadata + product roster ---
if (collectionMatch && isCollectionJson) {
  const c = json.collection;
  const title = (c.title || '').trim();
  const bodyText = htmlToText(c.body_html || '');
  const handle = c.handle || collectionMatch[1];

  const limit = Number(cfg.collectionProductsLimit) || 250;
  const origin = (canonicalUrl.match(/^(https?:\/\/[^\/]+)/) || [])[1] || '';
  const productsUrl = origin + '/collections/' + handle + '/products.json?limit=' + limit;
  let prodList = [];
  const productsResp = await fetchJson(productsUrl);
  if (productsResp && Array.isArray(productsResp.products)) {
    prodList = productsResp.products;
  }

  const lines = [];
  if (title) lines.push(`# ${title}`);
  if (bodyText) {
    // Prefix every paragraph with the collection title (same reasoning as products).
    const titlePrefix = title ? `# ${title} \u2014 ` : '';
    const paragraphs = bodyText.split(/\n\n+/);
    for (const para of paragraphs) {
      const trimmed = para.trim();
      if (!trimmed) continue;
      lines.push('');
      lines.push(titlePrefix + trimmed);
    }
  }
  if (prodList.length) {
    lines.push('');
    lines.push('Products in this collection:');
    for (const pr of prodList) {
      const t = (pr.title || '').trim();
      if (!t) continue;
      const variants = Array.isArray(pr.variants) ? pr.variants : [];
      const prices = variants.map(v => Number(v && v.price)).filter(n => isFinite(n) && n > 0);
      const pmin = prices.length ? Math.min(...prices) : null;
      const pmax = prices.length ? Math.max(...prices) : null;
      const phandle = pr.handle || '';
      const purl = origin + '/products/' + phandle;
      let priceStr = '';
      if (pmin != null) {
        priceStr = (pmax != null && pmax !== pmin)
          ? ` — $${fmtMoney(pmin)}–$${fmtMoney(pmax)}`
          : ` — $${fmtMoney(pmin)}`;
      }
      lines.push(`- ${t}${priceStr} — ${purl}`);
    }
  }

  const composed = lines.join('\n');
  if (composed.length < 40) {
    return [{ json: { url: canonicalUrl, skip: true, skipReason: 'collection doc too small' } }];
  }

  const lastModified = c.updated_at || lastModifiedHttp || urlInfo.lastmod || null;

  return [{
    json: {
      url: canonicalUrl,
      page_title: title || null,
      meta_description: null,
      last_modified: lastModified,
      content: composed,
      content_hash: cyrb128(composed),
      char_count: composed.length,
      doc_type: 'collection',
      product_handle: null,
      collection_handle: handle,
      price_min: null,
      price_max: null,
      skip: false
    }
  }];
}

// --- HTML fallback for non-Shopify-JSON pages (home, /pages/*, blog) ---
const html = bodyRaw;
const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const pageTitle = (titleMatch ? titleMatch[1] : '').replace(/\s+/g, ' ').trim();
const descMatch = html.match(/<meta\s+name=["']description["']\s+content=["']([^"']+)["']/i);
const metaDescription = descMatch ? descMatch[1].trim() : '';
const text = htmlToText(html);
if (text.length < 80) {
  return [{ json: { url: canonicalUrl, skip: true, skipReason: 'empty or nearly empty body' } }];
}
const composed = [pageTitle && `# ${pageTitle}`, metaDescription, text].filter(Boolean).join('\n\n');

return [{
  json: {
    url: canonicalUrl,
    page_title: pageTitle || null,
    meta_description: metaDescription || null,
    last_modified: urlInfo.lastmod || lastModifiedHttp || null,
    content: composed,
    content_hash: cyrb128(composed),
    char_count: composed.length,
    doc_type: 'page',
    product_handle: null,
    collection_handle: null,
    price_min: null,
    price_max: null,
    skip: false
  }
}];

// Aggregate per-page results into a final report.
const items = $input.all();
const pagesAttempted = items.length;
const pagesIndexed = items.filter(i => !i.json.skip).length;
const pagesSkipped = items.filter(i => i.json.skip).length;
const totalChars = items.reduce((s, i) => s + (i.json.char_count || 0), 0);
// Estimate: text-embedding-3-small is ~$0.02 per 1M tokens, ~4 chars/token
const estTokens = Math.round(totalChars / 4);
const estCostUsd = +(estTokens / 1_000_000 * 0.02).toFixed(4);
const startedAt = $('Indexing Config').first().json.startedAt;
const durationSeconds = Math.round((Date.now() - new Date(startedAt).getTime()) / 1000);

const skippedDetail = items.filter(i => i.json.skip)
  .map(i => `${i.json.url} — ${i.json.skipReason}`)
  .slice(0, 20);

return [{
  json: {
    pagesAttempted,
    pagesIndexed,
    pagesSkipped,
    totalChars,
    estTokens,
    estCostUsd,
    durationSeconds,
    skippedDetail,
    startedAt,
    finishedAt: new Date().toISOString()
  }
}];
